-- EXPAND: add the column, deploy code that writes it
ALTER TABLE users ADD COLUMN email_verified boolean;

-- MIGRATE: backfill in batches, deploy code that reads it
--   (see the batched backfill step below)

-- CONTRACT: once old code is gone, enforce and clean up
ALTER TABLE users ALTER COLUMN email_verified SET DEFAULT false;

-- Give up if the lock can't be had within 5s
SET lock_timeout = '5s';
-- Cap how long any single statement runs
SET statement_timeout = '30s';

ALTER TABLE orders ADD COLUMN discount_cents integer;

-- Fast on PG 11+: constant default, metadata only
ALTER TABLE events ADD COLUMN source text DEFAULT 'web' NOT NULL;

-- Slow: a volatile default rewrites every row and holds the lock the whole time
-- ALTER TABLE events ADD COLUMN created_at timestamptz DEFAULT now() NOT NULL;

-- Safe version: add nullable, backfill in batches, then set default/not null later
ALTER TABLE events ADD COLUMN created_at timestamptz;

-- Build without blocking writes (cannot run inside a transaction)
CREATE INDEX CONCURRENTLY idx_orders_customer_id ON orders (customer_id);

-- If it failed partway, you get an INVALID index. Find it:
SELECT indexrelid::regclass AS index, indrelid::regclass AS table
FROM pg_index WHERE NOT indisvalid;

-- Drop the broken one (also concurrently) and retry the build
DROP INDEX CONCURRENTLY idx_orders_customer_id;

-- 1. Add the constraint without scanning (brief lock, no table scan)
ALTER TABLE users
  ADD CONSTRAINT users_email_not_null CHECK (email IS NOT NULL) NOT VALID;

-- 2. Validate it without blocking reads or writes
ALTER TABLE users VALIDATE CONSTRAINT users_email_not_null;

-- 3. PG 12+: now SET NOT NULL is cheap, it reuses the validated check
ALTER TABLE users ALTER COLUMN email SET NOT NULL;
ALTER TABLE users DROP CONSTRAINT users_email_not_null;

-- 1. Enforce for new and changed rows immediately, skip the scan of existing rows
ALTER TABLE orders
  ADD CONSTRAINT orders_customer_fk
  FOREIGN KEY (customer_id) REFERENCES customers (id) NOT VALID;

-- 2. Check existing rows without blocking writes
ALTER TABLE orders VALIDATE CONSTRAINT orders_customer_fk;

-- EXPAND: add the new column
ALTER TABLE events ADD COLUMN id_bigint bigint;

-- MIGRATE: app writes both columns; backfill old rows in batches
UPDATE events SET id_bigint = id
WHERE id_bigint IS NULL AND id BETWEEN $1 AND $2;

-- CONTRACT: after reads move over, swap the columns (metadata-only, fast)
ALTER TABLE events DROP COLUMN id;
ALTER TABLE events RENAME COLUMN id_bigint TO id;

-- A procedure can COMMIT mid-loop (PG 11+), so each batch releases its locks
CREATE PROCEDURE backfill_created_at() LANGUAGE plpgsql AS $$
DECLARE
  rows integer;
BEGIN
  LOOP
    UPDATE events SET created_at = inserted_at
    WHERE id IN (
      SELECT id FROM events WHERE created_at IS NULL
      ORDER BY id LIMIT 10000
    );
    GET DIAGNOSTICS rows = ROW_COUNT;
    EXIT WHEN rows = 0;
    COMMIT;                 -- release locks, let replicas and autovacuum catch up
    PERFORM pg_sleep(0.5);
  END LOOP;
END;
$$;

CALL backfill_created_at();

-- Don't: this breaks every old pod mid-deploy
-- ALTER TABLE users RENAME COLUMN signup_date TO created_at;

-- Do: add the new column, keep both in sync, retire the old one later
ALTER TABLE users ADD COLUMN created_at timestamptz;
-- backfill + dual-write, then much later:
ALTER TABLE users DROP COLUMN signup_date;

-- For a table rename, a view bridges old code to the new name
ALTER TABLE accounts RENAME TO orgs;
CREATE VIEW accounts AS SELECT * FROM orgs;

-- Find queries still referencing the column (needs pg_stat_statements)
SELECT query, calls
FROM pg_stat_statements
WHERE query ILIKE '%legacy_status%'
ORDER BY calls DESC;

-- Check for dependent views, constraints, or defaults
SELECT * FROM information_schema.view_column_usage
WHERE column_name = 'legacy_status';

-- Safe to drop only after the deprecation window
ALTER TABLE users DROP COLUMN legacy_status;

