-- No BEGIN/COMMIT here; golang-migrate skips the wrapping txn for this file
CREATE INDEX CONCURRENTLY idx_orders_customer_id ON orders (customer_id);

-- Session 1: start the change but don't commit yet
BEGIN;
ALTER TABLE orders ADD COLUMN discount_cents integer;

-- Session 2: see exactly which lock it holds and on what
SELECT relation::regclass, mode, granted
FROM pg_locks
WHERE pid = <migration_pid> AND relation IS NOT NULL;

-- Session 1: roll back the rehearsal (or commit once you're happy)
ROLLBACK;
